INSERT INTO mytyles_vitrified_tiles (id, category, product_name, price, description, colors, styles, image_url, filter_size, url) VALUES
(1,'Tiles / Vitrified Tiles','Vitrified White Slab Floor and Wall Tile Code29234 (790x3000x15mm, Matt)',327,'Introduce timeless elegance to your interiors with this 2.5x10 feet marble-look slab tile featuring a sophisticated matte finish. The large slab format reduces grout lines, creating a smooth, expansive look that enhances the natural marble effect. The matte finish adds a subtle, understated elegance, perfect for contemporary and classic designs alike. Ideal for use on walls, floors, or countertops, this tile combines the beauty of marble with the durability of tile, making it a versatile choice for residential and commercial spaces.','Red, White','Contemporary, Marble, Matte, Natural, Vitrified','https://corewebimage1.mytyles.biz/storage/prod/public/products/images/0a53455-1784-1bad-d7-bdda10eee57/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/1d12e46-1c63-c857-8c5-424086c8551/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/1fcce-a387-6c2-1421-a57cfe3f558b/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/41ed-afa4-d50-0ccf-83ecfbdaad2c/1200x1200.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/41ed-afa4-d50-0ccf-83ecfbdaad2c/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/4fa8ed8-f8b-a4bb-b2db-21c2a007057/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/6bbca08-aa4d-55eb-7df0-a40f31bbcec3/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/6f8c21c-8a85-8ef1-6530-0edbd6d84308/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/77650d-3b5-fed6-34a1-0ca238ddc8fc/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/88fb7a-a220-84e-4161-a7b221d632df/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/a4407a-35ea-8e77-5e1e-ec6566dcea1a/60