INSERT INTO mytyles_vitrified_tiles (id, category, product_name, price, description, colors, styles, image_url, filter_size, url) VALUES
(101,'Tiles / Vitrified Tiles / Marble Vitrified Tiles','Vitrified Half White Slab Floor and Wall Tile Code35080 (1200x2400mm, Matt)',207,'The 4x8 feet marble design slab tile in a matte finish combines the luxurious look of natural marble with the durability and practicality of modern tile. Perfect for both floor and wall applications, this large-format tile minimizes grout lines, offering a seamless and sophisticated appearance. The matte finish provides a soft, non-reflective surface that enhances the natural stone look while reducing glare, making it ideal for creating a serene and elegant atmosphere. Designed for both residential and commercial spaces, these tiles are made from high-quality materials, ensuring they are moisture-resistant, durable, and easy to maintain. Whether used in living areas, bathrooms, or hallways, the marble design brings a timeless beauty that elevates any room. Experience timeless luxury with this stunning 4x8 ft marble tile. Crafted from premium natural marble, it showcases exquisite veining and a smooth polished finish, making it perfect for creating spacious, elegant floors or accent walls. Ideal for both residential and commercial interiors, this large-format tile adds a sense of grandeur and sophistication to any space.','Red, White','Marble, Matte, Modern, Natural, Polished, Stone Look, Vitrified','https://corewebimage1.mytyles.biz/storage/prod/public/products/images/1cbdc41-4d55-75c4-f3ef-848b058f0f1d/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/5f835a3-c71-2823-b3bf-12e02c74b03/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/676f2e3-7c3-ee8d-a5c3-4031bc4d21b3/1200x1200.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/676f2e3-7c3-ee8d-a5c3-4031bc4d21b3/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/public/products/images/67cc67-a146-e74e-6d01-247fd488e6/600x600.webp, https://corewebimage1.mytyles.biz/storage/prod/